'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { cn } from '@/lib/utils';
import { useState, useEffect } from 'react';
import ReactPlayer from 'react-player';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { ChevronDown, Menu, X, User, Volume2, VolumeX, LogOut, Settings } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useAuth } from '@/components/auth-provider';

const navItems = [
  { name: 'Profile', href: '/' },
  { name: 'Character', href: '/character' },
  { name: 'Log', href: '/log' },
  {
    name: 'Board',
    href: '/board',
    submenu: [
      { name: 'TRPG', href: '/board/trpg' },
      { name: 'Review', href: '/board/review' },
      { name: 'Music', href: '/board/music' },
    ],
  },
  { name: 'GuestBook', href: '/guestbook' },
];

export function Navigation() {
  const pathname = usePathname();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [bgmUrl, setBgmUrl] = useState<string | undefined>('');
  const [mounted, setMounted] = useState(false);
  const { user, logout, hasPermission } = useAuth();

  useEffect(() => {
    let isMounted = true;
    setMounted(true);

    const fetchSettings = async () => {
      try {
        const res = await fetch('/api/settings');
        if (!res.ok) {
          console.warn('Failed to fetch settings, status:', res.status);
          return;
        }

        const contentType = res.headers.get('content-type');
        if (contentType && contentType.includes('application/json')) {
          const data = await res.json();
          if (isMounted && data?.bgmUrl) {
            setBgmUrl(data.bgmUrl);
          }
        } else {
          console.warn('API /api/settings route did not return JSON');
        }
      } catch (err) {
        console.error('BGM fetch error:', err);
      }
    };

    fetchSettings();

    return () => {
      isMounted = false;
    };
  }, []);

  const toggleMusic = () => {
    if (bgmUrl) {
      setIsPlaying(!isPlaying);
    }
  };

  return (
    <header className="sticky top-0 z-50 w-full border-b border-border bg-card">
      <div className="container mx-auto px-4">
        <nav className="flex h-16 items-center justify-between">
          {/* Mobile Menu Button */}
          <Button
            variant="ghost"
            size="icon"
            className="md:hidden"
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
          >
            {mobileMenuOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
          </Button>

          {/* Desktop Navigation - Centered */}
          <ul className="hidden md:flex items-center gap-1 flex-1 justify-center">
            {navItems.map((item) => (
              <li key={item.name}>
                {item.submenu ? (
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <button
                        className={cn(
                          'flex items-center gap-1 px-4 py-2 text-sm font-medium transition-colors',
                          'hover:bg-primary hover:text-primary-foreground',
                          pathname.startsWith('/board')
                            ? 'bg-primary text-primary-foreground'
                            : 'text-foreground'
                        )}
                      >
                        {item.name}
                        <ChevronDown className="h-4 w-4" />
                      </button>
                    </DropdownMenuTrigger>
                    <DropdownMenuContent align="start" className="w-40">
                      {item.submenu.map((subitem) => (
                        <DropdownMenuItem key={subitem.name} asChild>
                          <Link
                            href={subitem.href}
                            className={cn(
                              'w-full cursor-pointer',
                              pathname === subitem.href && 'bg-primary/10'
                            )}
                          >
                            {subitem.name}
                          </Link>
                        </DropdownMenuItem>
                      ))}
                    </DropdownMenuContent>
                  </DropdownMenu>
                ) : (
                  <Link
                    href={item.href}
                    className={cn(
                      'block px-4 py-2 text-sm font-medium transition-colors',
                      'hover:bg-primary hover:text-primary-foreground',
                      (item.href === '/' ? pathname === '/' : pathname.startsWith(item.href))
                        ? 'bg-primary text-primary-foreground'
                        : 'text-foreground'
                    )}
                  >
                    {item.name}
                  </Link>
                )}
              </li>
            ))}
          </ul>

          {/* Right Side Icons */}
          <div className="flex items-center gap-2">
            {/* Music Toggle Button */}
            <Button
              variant="ghost"
              size="icon"
              onClick={toggleMusic}
              title={isPlaying ? '음악 끄기' : '음악 켜기'}
            >
              {isPlaying ? (
                <Volume2 className="h-5 w-5" />
              ) : (
                <VolumeX className="h-5 w-5" />
              )}
            </Button>

            {/* User Menu */}
            {user ? (
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" size="icon" title="사용자 메뉴">
                    <User className="h-5 w-5" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  <DropdownMenuItem disabled>
                    <span className="font-semibold">{user.name}</span> ({user.role})
                  </DropdownMenuItem>
                  {hasPermission(['SUPER_ADMIN', 'ADMIN', 'EDITOR', 'MANAGER']) && (
                    <DropdownMenuItem asChild>
                      <Link href="/admin">
                        <Settings className="mr-2 h-4 w-4" />
                        <span>관리자 페이지</span>
                      </Link>
                    </DropdownMenuItem>
                  )}
                  <DropdownMenuItem onClick={logout}>
                    <LogOut className="mr-2 h-4 w-4" />
                    <span>로그아웃</span>
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            ) : (
              <Button asChild variant="ghost" size="icon" title="로그인">
                <Link href="/login">
                  <User className="h-5 w-5" />
                </Link>
              </Button>
            )}
          </div>
        </nav>

        {/* Mobile Navigation */}
        {mobileMenuOpen && (
          <div className="md:hidden border-t border-border py-4">
            <ul className="flex flex-col gap-1">
              {navItems.map((item) => (
                <li key={item.name}>
                  {item.submenu ? (
                    <div>
                      <span className="block px-4 py-2 text-sm font-medium text-muted-foreground">
                        {item.name}
                      </span>
                      <ul className="pl-4">
                        {item.submenu.map((subitem) => (
                          <li key={subitem.name}>
                            <Link
                              href={subitem.href}
                              onClick={() => setMobileMenuOpen(false)}
                              className={cn(
                                'block px-4 py-2 text-sm transition-colors',
                                'hover:bg-primary hover:text-primary-foreground',
                                pathname === subitem.href
                                  ? 'bg-primary text-primary-foreground'
                                  : 'text-foreground'
                              )}
                            >
                              {subitem.name}
                            </Link>
                          </li>
                        ))}
                      </ul>
                    </div>
                  ) : (
                    <Link
                      href={item.href}
                      onClick={() => setMobileMenuOpen(false)}
                      className={cn(
                        'block px-4 py-2 text-sm font-medium transition-colors',
                        'hover:bg-primary hover:text-primary-foreground',
                        (item.href === '/' ? pathname === '/' : pathname.startsWith(item.href))
                          ? 'bg-primary text-primary-foreground'
                          : 'text-foreground'
                      )}
                    >
                      {item.name}
                    </Link>
                  )}
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
      {mounted && bgmUrl && (
        <ReactPlayer
          url={bgmUrl}
          playing={isPlaying}
          loop={true}
          width="0"
          height="0"
          volume={1}
          style={{ display: 'none' }}
        />
      )}
    </header>
  );
}
